<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Maintenance Work Orders</h1><p class="text-muted mb-0">Vehicle and equipment maintenance, because tools apparently object to immortality.</p></div><button class="btn btn-primary" data-bs-toggle="modal" data-bs-target="#newMwo"><i class="fa-solid fa-plus me-2"></i>New Work Order</button></div>
<div class="card"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Work Order</th><th>Asset</th><th>Title</th><th>Priority</th><th>Scheduled</th><th>Status</th><th>Cost</th><th></th></tr></thead><tbody><?php foreach($orders as $o):?><tr><td><strong><?=e($o['work_order_number'])?></strong></td><td><?=e($o['unit_number']?:$o['equipment_name'])?></td><td><?=e($o['title'])?><small class="d-block text-muted"><?=e($o['assigned_name'])?></small></td><td><span class="badge text-bg-<?=$o['priority']==='urgent'?'danger':($o['priority']==='high'?'warning':'secondary')?>"><?=e($o['priority'])?></span></td><td><?=e($o['scheduled_date'])?></td><td><?=e($o['status'])?></td><td><?=money($o['actual_cost']?:$o['estimated_cost'])?></td><td><form class="d-flex gap-1" method="post" action="/portal/maintenance/<?=$o['id']?>"><?=csrf_field()?><select name="status" class="form-select form-select-sm"><?php foreach(['open','scheduled','in_progress','completed','cancelled'] as $v):?><option <?=selected($o['status'],$v)?>><?=$v?></option><?php endforeach?></select><input type="hidden" name="priority" value="<?=e($o['priority'])?>"><input type="hidden" name="scheduled_date" value="<?=e($o['scheduled_date'])?>"><input type="hidden" name="actual_cost" value="<?=e($o['actual_cost'])?>"><input type="hidden" name="assigned_user_id" value="<?=e($o['assigned_user_id'])?>"><button class="btn btn-sm btn-outline-primary">Save</button></form></td></tr><?php endforeach?></tbody></table></div></div>
<div class="modal fade" id="newMwo"><div class="modal-dialog modal-lg"><form class="modal-content" method="post" action="/portal/maintenance"><?=csrf_field()?><div class="modal-header"><h2 class="modal-title h5">New Maintenance Work Order</h2><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="row g-3"><div class="col-md-4"><label class="form-label">Asset type</label><select class="form-select" name="asset_type"><option value="vehicle">Vehicle</option><option value="equipment">Equipment</option></select></div><div class="col-md-4"><label class="form-label">Vehicle</label><select class="form-select" name="vehicle_id"><option value="">None</option><?php foreach($vehicles as $v):?><option value="<?=$v['id']?>"><?=e($v['unit_number'])?></option><?php endforeach?></select></div><div class="col-md-4"><label class="form-label">Equipment</label><select class="form-select" name="inventory_item_id"><option value="">None</option><?php foreach($items as $i):?><option value="<?=$i['id']?>"><?=e($i['name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Title</label><input required class="form-control" name="title"></div><div class="col-12"><label class="form-label">Description</label><textarea class="form-control" name="description"></textarea></div><div class="col-md-3"><label class="form-label">Priority</label><select class="form-select" name="priority"><option>normal</option><option>low</option><option>high</option><option>urgent</option></select></div><div class="col-md-3"><label class="form-label">Scheduled</label><input type="date" class="form-control" name="scheduled_date"></div><div class="col-md-3"><label class="form-label">Est. cost</label><input type="number" step=".01" class="form-control" name="estimated_cost"></div><div class="col-md-3"><label class="form-label">Assigned to</label><select class="form-select" name="assigned_user_id"><option value="">Unassigned</option><?php foreach($users as $u):?><option value="<?=$u['id']?>"><?=e($u['name'])?></option><?php endforeach?></select></div></div></div><div class="modal-footer"><button class="btn btn-primary">Create Work Order</button></div></form></div></div>
